using Contoso.Scoring;

namespace Contoso.Scoring.Tests;

[TestClass]
public sealed class ScoreCalculatorTests
{
    private readonly ScoreCalculator _calculator = new();

    // ── CalculatePercentage: boundary and range checks ──

    [TestMethod]
    [DataRow(7, 10, 70.0)]
    [DataRow(10, 10, 100.0)]
    [DataRow(0, 10, 0.0)]
    [DataRow(1, 3, 33.333333333333336)]
    public void CalculatePercentage_ValidInputs_ReturnsExpected(int correct, int total, double expected)
    {
        var result = _calculator.CalculatePercentage(correct, total);
        Assert.AreEqual(expected, result);
    }

    [TestMethod]
    public void CalculatePercentage_Result_IsInValidRange()
    {
        var result = _calculator.CalculatePercentage(7, 10);

        Assert.IsGreaterThan(0.0, result);
        Assert.IsLessThan(100.0, result);
        Assert.IsInRange(result, 0.0, 100.0);
    }

    [TestMethod]
    public void CalculatePercentage_PerfectScore_IsExactly100()
    {
        var result = _calculator.CalculatePercentage(10, 10);

        Assert.IsGreaterThan(99.0, result);
        Assert.IsLessThan(101.0, result);
        Assert.AreEqual(100.0, result);
    }

    [TestMethod]
    public void CalculatePercentage_ZeroCorrect_ReturnsZero()
    {
        var result = _calculator.CalculatePercentage(0, 5);
        Assert.AreEqual(0.0, result);
    }

    [TestMethod]
    public void CalculatePercentage_ZeroTotal_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculatePercentage(0, 0));
    }

    [TestMethod]
    public void CalculatePercentage_NegativeTotal_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculatePercentage(0, -1));
    }

    [TestMethod]
    public void CalculatePercentage_NegativeCorrect_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculatePercentage(-1, 10));
    }

    [TestMethod]
    public void CalculatePercentage_CorrectExceedsTotal_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculatePercentage(11, 10));
    }

    // ── GetGrade: boundary tests at each grade threshold ──

    [TestMethod]
    [DataRow(90.0, "A")]
    [DataRow(95.0, "A")]
    [DataRow(100.0, "A")]
    [DataRow(80.0, "B")]
    [DataRow(89.99, "B")]
    [DataRow(70.0, "C")]
    [DataRow(79.99, "C")]
    [DataRow(60.0, "D")]
    [DataRow(69.99, "D")]
    [DataRow(59.99, "F")]
    [DataRow(0.0, "F")]
    public void GetGrade_AtBoundaries_ReturnsCorrectGrade(double percentage, string expected)
    {
        var grade = _calculator.GetGrade(percentage);
        Assert.AreEqual(expected, grade);
    }

    // ── NormalizeScore: range and clamping checks ──

    [TestMethod]
    public void NormalizeScore_NormalInput_ReturnsValueInRange()
    {
        var result = _calculator.NormalizeScore(75, 100);

        Assert.IsInRange(result, 0.0, 100.0);
        Assert.AreEqual(75.0, result);
    }

    [TestMethod]
    public void NormalizeScore_ExceedsMax_ClampedTo100()
    {
        var result = _calculator.NormalizeScore(120, 100);

        Assert.IsLessThan(101.0, result);
        Assert.AreEqual(100.0, result);
    }

    [TestMethod]
    public void NormalizeScore_ZeroRaw_ReturnsZero()
    {
        var result = _calculator.NormalizeScore(0, 100);
        Assert.AreEqual(0.0, result);
    }

    [TestMethod]
    public void NormalizeScore_HalfOfMax_Returns50()
    {
        var result = _calculator.NormalizeScore(50, 100);

        Assert.IsGreaterThan(0.0, result);
        Assert.IsInRange(result, 49.0, 51.0);
        Assert.AreEqual(50.0, result);
    }

    [TestMethod]
    public void NormalizeScore_NegativeRaw_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.NormalizeScore(-1, 100));
    }

    [TestMethod]
    public void NormalizeScore_ZeroMax_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.NormalizeScore(50, 0));
    }

    [TestMethod]
    public void NormalizeScore_NegativeMax_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.NormalizeScore(50, -10));
    }
}

